const text = ($input.item.json.title + ' ' + ($input.item.json.contentSnippet || '')).toLowerCase();

const BUYER_KEYWORDS = {
  'need': 15, 'looking for': 15, 'hire': 20, 'budget': 20,
  'who can build': 25, 'help me': 10, 'recommend': 10,
  'want to': 10, 'searching for': 15, 'how much': 15,
  'agency': 10, 'developer': 10, 'freelancer': 10
};

const NICHE_KEYWORDS = {
  'dental': 'Dental', 'dentist': 'Dental', 'hvac': 'HVAC',
  'heating': 'HVAC', 'cooling': 'HVAC', 'lawyer': 'Legal',
  'law firm': 'Legal', 'attorney': 'Legal', 'real estate': 'Real Estate',
  'realtor': 'Real Estate', 'med spa': 'Med Spa', 'medspa': 'Med Spa',
  'property management': 'Real Estate'
};

let score = 0;
for (const [kw, pts] of Object.entries(BUYER_KEYWORDS)) {
  if (text.includes(kw)) score += pts;
}

let niche = 'General';
for (const [kw, label] of Object.entries(NICHE_KEYWORDS)) {
  if (text.includes(kw)) { niche = label; break; }
}

score = Math.min(score, 100);

return [{
  json: {
    ...$input.item.json,
    viper_score: score,
    niche: niche,
    is_high_intent: score >= 50
  }
}];
